import React, { useState, useEffect } from "react";
import axios from "axios";
import { useNavigate, useParams } from "react-router-dom";

const EditPost = ({ setPosts }) => {
  let { id } = useParams();
  const navigate = useNavigate();

  const initialState = {
    status_body: "",
    date: "",
    file: "",
  };

  const [formData, setFormData] = useState(initialState);

  const handleChange = (e) => {
    console.log(e.target);
    setFormData({ ...formData, [e.target.id]: e.target.value });
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    const media = new FormData();
    media.append("file", formData.file);
    media.append("name", formData.name);
    media.append("status_body", formData.status_body);
    media.append("date", formData.date);

    axios
      .put(`http://localhost:8000/bunnybook/posts/${id}/`, media)
      .then((res) => {
        setFormData(initialState);
        setPosts(res.data);
        navigate("/posts", { replace: true });
      });
  };

  useEffect(() => {
    axios.get(`http://localhost:8000/bunnybook/posts/${id}/`).then((res) => {
      setFormData(res.data);
      console.log(res.data)
    });
  }, [id]);

  // const handleFile = (e) => {
  //   console.log(e.target);
  //   setFormData({ ...formData, [e.target.id]: e.target.files[0] });
  // };

  return (
    <div className="lright">
      <form
        onSubmit={handleSubmit}
        encType="multipart/form-data"
        className="lbox"
      >
        <input
          id="status_body"
          name="status_body"
          type="text"
          className="linput"
          placeholder="Post"
          value={formData.status_body}
          onChange={handleChange}
        />
        <input
          className="linput"
          id="date"
          name="date"
          type="date"
          value={formData.date}
          placeholder="Date"
          onChange={handleChange}
        />
{/* 
        <input
          className="linput"
          name="media"
          id="media"
          type="file"
          value={formData.file}
          accept="video/*,image/*"
          onChange={handleFile}
        /> */}

        <button type="submit" className="signupbutton">
          {" "}
          Edit Post{" "}
        </button>
      </form>
    </div>
  );
};

export default EditPost;
